  \rho { \mathopen {} \left ( r { \mathopen {} \left ( \eta _{ I } a \right ) \mathclose {}} \right ) \mathclose {}} 
\end {aligned}

  \begin {aligned}
  \rho { \mathopen {} \left ( r { \mathopen {} \left ( \eta _{ I } a \right ) \mathclose {}} \right ) \mathclose {}} 
